import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import Login from './pages/Login';
import SignUp from './pages/SignUp';
import AdminDashboard from './pages/admin/Dashboard';
import AdminStudents from './pages/admin/Students';
import AdminRoutes from './pages/admin/Routes';
import AdminFees from './pages/admin/Fees';
import AdminSchedules from './pages/admin/Schedules';
import AdminUpcoming from './pages/admin/Upcoming';
import AdminOverdue from './pages/admin/Overdue';
import AdminProfile from './pages/admin/Profile';
import StudentDashboard from './pages/student/Dashboard';
import StudentFees from './pages/student/Fees';
import StudentSchedule from './pages/student/Schedule';
import StudentProfile from './pages/student/Profile';
import StudentNotifications from './pages/student/Notifications';
import Layout from './components/shared/Layout';
import Placeholder from './components/shared/Placeholder';
import './App.css';

const PrivateRoute = ({ children, adminOnly = false }) => {
  const { user, loading } = useAuth();
  if (loading) return <div className="loading-screen"><div className="spinner" /><p style={{ color:'var(--text-muted)', fontSize:14 }}>Loading...</p></div>;
  if (!user) return <Navigate to="/login" replace />;
  if (adminOnly && user.role !== 'admin') return <Navigate to="/student/dashboard" replace />;
  return children;
};

function AppRoutes() {
  const { user } = useAuth();
  return (
    <Routes>
      <Route path="/login" element={user ? <Navigate to={user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard'} /> : <Login />} />
      <Route path="/signup" element={user ? <Navigate to={user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard'} /> : <SignUp />} />
      <Route path="/admin" element={<PrivateRoute adminOnly><Layout /></PrivateRoute>}>
        <Route path="dashboard" element={<AdminDashboard />} />
        <Route path="students" element={<AdminStudents />} />
        <Route path="routes" element={<AdminRoutes />} />
        <Route path="fees" element={<AdminFees />} />
        <Route path="passes" element={<Placeholder title="Bus Pass Generation" description="Auto-issue digital bus passes and manage QR codes upon fee payment confirmation." icon="🎟️" />} />
        <Route path="reports" element={<Placeholder title="Reports & Analytics" description="View and export collection summary and pending dues by route/department." icon="📊" />} />
        <Route path="refunds" element={<Placeholder title="Refund & Cancellation" description="Process mid-term fee refund requests on route cancellation or withdrawal." icon="💸" />} />
        <Route path="schedules" element={<AdminSchedules />} />
        <Route path="upcoming" element={<AdminUpcoming />} />
        <Route path="overdue" element={<AdminOverdue />} />
        <Route path="profile" element={<AdminProfile />} />
      </Route>
      <Route path="/student" element={<PrivateRoute><Layout /></PrivateRoute>}>
        <Route path="dashboard" element={<StudentDashboard />} />
        <Route path="fees" element={<StudentFees />} />
        <Route path="schedule" element={<StudentSchedule />} />
        <Route path="passes" element={<Placeholder title="Digital Bus Pass" description="Download or print your digital bus pass. Valid after full fee payment." icon="📱" />} />
        <Route path="routes" element={<Placeholder title="Route Changes" description="View your route details, change requests, and available timings." icon="🗺️" />} />
        <Route path="concessions" element={<Placeholder title="Fee Concessions" description="Apply for category-based concessions (SC/ST, staff ward, sibling discount)." icon="📋" />} />
        <Route path="support" element={<Placeholder title="Support & Grievances" description="Raise complaints about fee issues, pass problems, or route difficulties." icon="🎧" />} />
        <Route path="profile" element={<StudentProfile />} />
        <Route path="notifications" element={<StudentNotifications />} />
      </Route>
      <Route path="*" element={<Navigate to="/login" replace />} />
    </Routes>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <AppRoutes />
      </BrowserRouter>
    </AuthProvider>
  );
}
